+    #[test]
+    fn test_order_by_equality_prefix_on_composite_index_uses_seek_without_sorter() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE messages (
+                id INTEGER PRIMARY KEY,
+                conversation_id INTEGER,
+                idx INTEGER,
+                role TEXT,
+                author TEXT,
+                created_at INTEGER,
+                content TEXT,
+                extra_json TEXT,
+                extra_bin BLOB
+            );",
+        )
+        .unwrap();
+        conn.execute("CREATE INDEX idx_messages_conv_idx ON messages(conversation_id, idx);")
+            .unwrap();
+        conn.execute(
+            "INSERT INTO messages
+                (id, conversation_id, idx, role, author, created_at, content, extra_json, extra_bin)
+             VALUES
+                (1, 7, 0, 'user', 'user', 1000, 'first', NULL, NULL),
+                (2, 7, 1, 'assistant', 'assistant', 1001, 'second', NULL, NULL),
+                (3, 8, 0, 'user', 'user', 1002, 'other', NULL, NULL);",
+        )
+        .unwrap();
+
+        let schema = conn.schema.borrow();
+        let messages = schema
+            .iter()
+            .find(|table| table.name.eq_ignore_ascii_case("messages"))
+            .expect("messages table should exist in schema");
+        let idx = messages
+            .indexes
+            .iter()
+            .find(|index| index.name.eq_ignore_ascii_case("idx_messages_conv_idx"))
+            .expect("messages(conversation_id, idx) index should exist in schema");
+        assert_eq!(idx.columns, vec!["conversation_id", "idx"]);
+        drop(schema);
+
+        let opcodes = explain_opcodes(
+            &conn,
+            "SELECT id, idx, role, author, created_at, content
+             FROM messages INDEXED BY idx_messages_conv_idx
+             WHERE conversation_id = 7 ORDER BY idx",
+        );
+        assert!(
+            opcodes.iter().any(|opcode| opcode == "SeekGE"),
+            "composite equality-prefix ORDER BY should seek into the index slice: {opcodes:?}"
+        );
+        assert!(
+            !opcodes.iter().any(|opcode| opcode == "SorterOpen"),
+            "composite equality-prefix ORDER BY should bypass sorter temp b-tree: {opcodes:?}"
+        );
+    }
